<section class="detail-hero" style="background-image:linear-gradient(90deg,rgba(0,0,0,.72),rgba(0,0,0,.15)),url('<?=Security::e($destination['image'])?>')"><div class="container"><small><?=Security::e($destination['province'])?></small><h1><?=Security::e($destination['name'])?></h1><p><?=Security::e($destination['description'])?></p></div></section><section class="container section two-col"><div><h2>Hospedajes</h2><?php foreach($hotels as $h):?><div class="list-item"><strong><?=Security::e($h['name'])?></strong><span>₡<?=number_format($h['price_per_night'])?> por noche</span></div><?php endforeach;?><h2>Actividades</h2><?php foreach($activities as $a):?><div class="list-item"><strong><?=Security::e($a['name'])?></strong><span>₡<?=number_format($a['price'])?></span></div><?php endforeach;?></div><aside><?php if($weather):?><div class="weather"><h3>Clima actual</h3><div class="temperature"><?=round($weather['temperature_2m'])?>°C</div><p>Humedad: <?=$weather['relative_humidity_2m']?>%</p><p>Viento: <?=$weather['wind_speed_10m']?> km/h</p></div><?php endif;?><iframe class="map" src="https://www.openstreetmap.org/export/embed.html?bbox=<?=$destination['longitude']-.04?>%2C<?=$destination['latitude']-.04?>%2C<?=$destination['longitude']+.04?>%2C<?=$destination['latitude']+.04?>&layer=mapnik&marker=<?=$destination['latitude']?>%2C<?=$destination['longitude']?>"></iframe><a class="btn full" href="index.php?route=reservation/create">Reservar ahora</a></aside></section>
